    <script>
        // Cart management
        let cart = JSON.parse(localStorage.getItem('cart')) || [];

        function addToCart(product) {
            cart.push(product);
            localStorage.setItem('cart', JSON.stringify(cart));
            showNotification(`${product} added to cart!`);
        }

        function openCart() {
            const cartModal = document.getElementById('cartModal');
            const cartItems = document.getElementById('cartItems');
            const cartTotal = document.getElementById('cartTotal');

            if (cart.length === 0) {
                cartItems.innerHTML = '<p>Your cart is empty</p>';
                cartTotal.innerHTML = '';
            } else {
                const prices = {
                    'Ethiopian Highlands': 16.99,
                    'Dark Roast Blend': 14.99,
                    'Organic Fair Trade': 18.99,
                    'Colombian Reserve': 17.99,
                    'Cold Brew': 12.99,
                    'Gift Bundle': 49.99
                };

                let html = '<ul style="list-style: none;">';
                let total = 0;
                const uniqueItems = {};

                cart.forEach(item => {
                    uniqueItems[item] = (uniqueItems[item] || 0) + 1;
                    total += prices[item] || 0;
                });

                for (const [item, quantity] of Object.entries(uniqueItems)) {
                    html += `<li style="padding: 0.5rem 0; border-bottom: 1px solid #eee;">
                        ${item} (x${quantity}) - $${((prices[item] || 0) * quantity).toFixed(2)}
                        <button onclick="removeFromCart('${item}')" style="float: right; background: var(--accent); color: white; border: none; padding: 0.3rem 0.8rem; border-radius: 4px; cursor: pointer;">Remove</button>
                    </li>`;
                }
                html += '</ul>';
                cartItems.innerHTML = html;
                cartTotal.innerHTML = `Total: $${total.toFixed(2)}`;
            }

            cartModal.style.display = 'block';
        }

        function closeCart() {
            document.getElementById('cartModal').style.display = 'none';
        }

        function removeFromCart(product) {
            const index = cart.indexOf(product);
            if (index > -1) {
                cart.splice(index, 1);
                localStorage.setItem('cart', JSON.stringify(cart));
                openCart();
            }
        }

        function checkout() {
            showNotification('Taking you to checkout...');
            setTimeout(() => {
                closeCart();
                cart = [];
                localStorage.setItem('cart', JSON.stringify(cart));
            }, 1500);
        }

        // Login management
        function openLogin() {
            document.getElementById('loginModal').style.display = 'block';
        }

        function closeLogin() {
            document.getElementById('loginModal').style.display = 'none';
        }

        function handleLogin(event) {
            event.preventDefault();
            showNotification('Welcome back! 👋');
            closeLogin();
        }

        // Hamburger menu
        document.getElementById('hamburger').addEventListener('click', function() {
            const navMenu = document.getElementById('navMenu');
            navMenu.classList.toggle('active');
        });

        // Close menu when link is clicked
        document.querySelectorAll('#navMenu a').forEach(link => {
            link.addEventListener('click', () => {
                document.getElementById('navMenu').classList.remove('active');
            });
        });

        // Notification system
        function showNotification(message) {
            const notification = document.createElement('div');
            notification.className = 'notification';
            notification.textContent = message;
            document.body.appendChild(notification);

            setTimeout(() => {
                notification.remove();
            }, 3000);
        }

        // Other functions
        function openShop() {
            document.getElementById('products').scrollIntoView({ behavior: 'smooth' });
        }

        function joinLoyalty() {
            showNotification('Redirecting to loyalty program signup...');
        }

        function searchFunction() {
            showNotification('Search functionality coming soon!');
        }

        function subscribeNewsletter(event) {
            event.preventDefault();
            const email = event.target.querySelector('input[type="email"]').value;
            showNotification(`Thanks for subscribing, ${email}!`);
            event.target.reset();
        }

        function showSignup() {
            showNotification('Sign up form coming soon!');
        }

        // Scroll reveal animation
        const revealElements = document.querySelectorAll('.scroll-reveal');

        const revealOnScroll = () => {
            revealElements.forEach(element => {
                const windowHeight = window.innerHeight;
                const revealTop = element.getBoundingClientRect().top;

                if (revealTop < windowHeight - 50) {
                    element.classList.add('active');
                }
            });
        };

        window.addEventListener('scroll', revealOnScroll);
        revealOnScroll(); // Call once on load

        // Close modals when clicking outside
        window.addEventListener('click', function(event) {
            const loginModal = document.getElementById('loginModal');
            const cartModal = document.getElementById('cartModal');

            if (event.target === loginModal) {
                loginModal.style.display = 'none';
            }
            if (event.target === cartModal) {
                cartModal.style.display = 'none';
            }
        });
    </script>
</body>
</html>
