fun predictBatch(inputs: Array<ByteBuffer>): Array<FloatArray> {
    val batchSize = inputs.size
    val output = Array(batchSize) { FloatArray(outputSize) }

    for ((index, input) in inputs.withIndex()) {
        interpreter.run(input, arrayOf(output[index]))
    }

    return output
}
