    fun processOutput(
        detections: Array<FloatArray>,
        threshold: Float = 0.5f
    ): List<DetectionResult> {
        return detections
            .filter { it[4] > threshold } // confidence
            .map { detection ->
                DetectionResult(
                    boundingBox = RectF(
                        detection[0],
                        detection[1],
                        detection[2],
                        detection[3]
                    ),
                    className = classNames[detection[5].toInt()],
                    confidence = detection[4]
                )
            }
    }
}
